// Clear stale subfolder cache at the start of each run
const store = $getWorkflowStaticData('global');
store.transcriptsFolderId = null;
store.summariesFolderId = null;
store.brandFolderIdForRun = null;

const transcript = $input.first().json.data.transcript;
const attendees = transcript.meeting_attendees || [];

// Use meeting_attendees — clean individual objects
const participantEmails = [...new Set(
  attendees.map(a => (a.email || '').trim().toLowerCase()).filter(e => e)
)];

const allInternal = participantEmails.length > 0 &&
  participantEmails.every(e => e.endsWith('@growisto.com'));

return [{ json: {
  meetingId: transcript.id,
  meetingTitle: transcript.title,
  meetingDate: transcript.date,
  participantEmails,
  sentences: transcript.sentences || [],
  isInternalCall: allInternal
} }];

const data = $input.first().json;
const title = data.meetingTitle || '';
const emails = data.participantEmails || [];
const personalDomains = ['gmail.com','yahoo.com','hotmail.com','outlook.com','icloud.com','yahoo.co.in','googlemail.com'];

const externalEmails = emails.filter(e => {
  const lower = e.toLowerCase();
  if (lower.endsWith('@growisto.com')) return false;
  const domain = lower.split('@')[1] || '';
  return !personalDomains.includes(domain);
});

const rawDomain = externalEmails.length > 0 ? (externalEmails[0].split('@')[1] || '').split('.')[0] : '';

let brandHint = rawDomain;
let noSignal = false;
if (!brandHint) {
  if (title.includes('<>')) {
    const parts = title.split('<>').map(p => p.trim());
    const clientPart = parts.find(p => !p.toLowerCase().includes('growisto')) || parts[parts.length - 1];
    brandHint = clientPart.trim();
  } else {
    brandHint = title;
  }
  noSignal = true;
}

return [{ json: { ...data, brandHint, rawDomain, noSignal } }];

const store = $getWorkflowStaticData('global');
const TTL = 24 * 60 * 60 * 1000;
const now = Date.now();
const data = $input.first().json;
const cacheHit = !!(store.folderCache && store.folderCacheTime && (now - store.folderCacheTime) < TTL);
return [{ json: { ...data, folders: cacheHit ? store.folderCache : null, cacheHit } }];

const store = $getWorkflowStaticData('global');
const driveItems = $input.all();
const folders = driveItems.map(item => ({ id: item.json.id, name: item.json.name }));
store.folderCache = folders;
store.folderCacheTime = Date.now();
const meetingData = $('Extract Brand Hint').first().json;
return [{ json: { ...meetingData, folders, cacheHit: false } }];

let raw = $input.first().json.content?.[0]?.text || '{}';
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();
let parsed;
try { parsed = JSON.parse(raw); } catch(e) { parsed = { matched_folder: null, confidence: 'low', reasoning: 'Failed to parse Claude response', is_new_brand: false }; }
const meetingData = $('Extract Brand Hint').first().json;
const store = $getWorkflowStaticData('global');
const folders = store.folderCache || [];
const matchedFolderObj = folders.find(f => f.name === parsed.matched_folder);
return [{ json: { ...meetingData, folders, matchedFolder: parsed.matched_folder, matchedFolderId: matchedFolderObj?.id || null, confidence: parsed.confidence, reasoning: parsed.reasoning, isNewBrand: parsed.is_new_brand } }];

const claudioData = $('Parse Brand Disambiguation').first().json;
const item = $input.first().json;
const brandFolderId = item.id || claudioData.matchedFolderId;
const store = $getWorkflowStaticData('global');
store.brandFolderIdForRun = brandFolderId;
if (claudioData.isNewBrand) { store.folderCacheTime = 0; }
return [{ json: { ...claudioData, brandFolderId } }];

const items = $input.all();
const brandData = $('Set Brand Folder ID').first().json;
const transcriptsItem = items.find(i => i.json.name?.toLowerCase().includes('transcript'));
const summariesItem = items.find(i => i.json.name?.toLowerCase().includes('summar'));
const store = $getWorkflowStaticData('global');
store.transcriptsFolderId = transcriptsItem?.json?.id || null;
store.summariesFolderId = summariesItem?.json?.id || null;
return [{ json: { ...brandData, transcriptsFolderId: transcriptsItem?.json?.id || null, summariesFolderId: summariesItem?.json?.id || null, needsTranscripts: !transcriptsItem, needsSummaries: !summariesItem } }];

const store = $getWorkflowStaticData('global');
const resolveData = $('Resolve Subfolder IDs').first().json;
const item = $input.first().json;
if (item.id && !item.meetingId) { store.transcriptsFolderId = item.id; }
return [{ json: { ...resolveData, transcriptsFolderId: store.transcriptsFolderId || resolveData.transcriptsFolderId } }];

const store = $getWorkflowStaticData('global');
const item = $input.first().json;
const summariesCheckData = $('Continue to Summaries Check').first().json;

// Always derive transcriptsFolderId from Continue to Summaries Check —
// it captures both the pre-existing ID and any freshly created ID.
const transcriptsFolderId = summariesCheckData.transcriptsFolderId || null;

// summariesFolderId: if item passed through from Summaries Subfolder Missing? it
// already carries summariesFolderId; if it came from Create Summaries Subfolder,
// item.id is the newly created folder — never fall back to stale store data.
const summariesFolderId = item.summariesFolderId || item.id || null;

// Keep store in sync with current run
if (transcriptsFolderId) store.transcriptsFolderId = transcriptsFolderId;
if (summariesFolderId) store.summariesFolderId = summariesFolderId;

const brandData = $('Set Brand Folder ID').first().json;
return [{ json: { ...brandData, brandFolderId: summariesCheckData.brandFolderId, transcriptsFolderId, summariesFolderId } }];

const data = $input.first().json;
const sentences = data.sentences || [];
const transcriptText = sentences.length > 0
  ? sentences.map(s => (s.speaker_name || 'Unknown') + ': ' + s.text).join('\n')
  : '[No transcript sentences available]';
const dateStr = data.meetingDate ? new Date(data.meetingDate).toISOString().split('T')[0] : new Date().toISOString().split('T')[0];
const { sentences: _dropped, ...rest } = data;
return [{ json: { ...rest, transcriptText, dateStr } }];

const summaryText = $input.first().json.content?.[0]?.text || 'Summary not available.';
const meetingData = $('Build Transcript Text').first().json;
// Always get summariesFolderId from Finalize Folder IDs — never from the store
// (store values can be stale from previous runs; Finalize Folder IDs is authoritative for this run)
const summariesFolderId = $('Finalize Folder IDs').first().json.summariesFolderId;
const summariesFolderLink = 'https://drive.google.com/drive/folders/' + summariesFolderId;
return [{ json: { ...meetingData, summaryText, summariesFolderId, summariesFolderLink } }];

const meetingData = $('Convert Summary to HTML').first().json;
const rawEmails = meetingData.participantEmails || [];

// Split any comma/semicolon/space-separated strings, flatten, deduplicate, filter @growisto.com
const seen = new Set();
const growistoAttendees = [];

for (const entry of rawEmails) {
  const parts = String(entry == null ? '' : entry).split(/[,;\s]+/);
  for (const part of parts) {
    const email = part.trim().toLowerCase();
    if (!email || !email.includes('@')) continue;
    if (!email.endsWith('@growisto.com')) continue;
    if (seen.has(email)) continue;
    seen.add(email);
    growistoAttendees.push(email);
  }
}

return [{ json: { ...meetingData, growistoAttendees, hasGrowistoAttendees: growistoAttendees.length > 0 } }];

const data = $input.first().json;
const md = data.summaryText || '';

function mdToHtml(text) {
  return text
    .replace(/^#### (.+)$/gm, '<h4>$1</h4>')
    .replace(/^### (.+)$/gm, '<h3>$1</h3>')
    .replace(/^## (.+)$/gm, '<h2 style="color:#1F3864;border-bottom:1px solid #ccc;padding-bottom:4px">$1</h2>')
    .replace(/^# (.+)$/gm, '<h1 style="color:#1F3864">$1</h1>')
    .replace(/\*\*(.+?)\*\*/g, '<b>$1</b>')
    .replace(/\*(.+?)\*/g, '<i>$1</i>')
    .replace(/^---$/gm, '<hr style="border:none;border-top:1px solid #eee;margin:12px 0">')
    .replace(/((?:^\|.+\|\n?)+)/gm, (match) => {
      const rows = match.trim().split('\n').filter(r => !/^\|[-| :]+\|$/.test(r));
      const htmlRows = rows.map((row, i) => {
        const cells = row.split('|').filter((_, idx, arr) => idx > 0 && idx < arr.length - 1);
        const tag = i === 0 ? 'th' : 'td';
        const style = i === 0 ? 'background:#1F3864;color:#fff;padding:6px 10px;text-align:left' : 'padding:6px 10px;border-bottom:1px solid #eee';
        return '<tr>' + cells.map(c => '<' + tag + ' style="' + style + '">' + c.trim() + '</' + tag + '>').join('') + '</tr>';
      });
      return '<table style="border-collapse:collapse;width:100%;margin:12px 0">' + htmlRows.join('') + '</table>';
    })
    .replace(/^[*-] (.+)$/gm, '<li>$1</li>')
    .replace(/(<li>.*<\/li>\n?)+/g, (match) => '<ul style="margin:6px 0;padding-left:20px">' + match + '</ul>')
    .replace(/`(.+?)`/g, '<code style="background:#f4f4f4;padding:1px 4px;border-radius:3px;font-size:0.9em">$1</code>')
    .replace(/\n{2,}/g, '</p><p style="margin:8px 0">')
    .replace(/\n/g, '<br>')
    .replace(/^/, '<p style="margin:8px 0">')
    .replace(/$/, '</p>');
}

const summaryHtml = '<div style="font-family:Arial,sans-serif;font-size:14px;line-height:1.6;color:#333;max-width:800px">' + mdToHtml(md) + '</div>';

return [{ json: { ...data, summaryHtml } }];

const items = $input.all();
const mdFiles = items.filter(item => item.json.name && item.json.name.endsWith('.md'));
if (mdFiles.length === 0) {
  return [{ json: { hasPreviousSummary: false, latestSummaryId: null, latestSummaryName: null } }];
}
mdFiles.sort((a, b) => new Date(b.json.createdTime) - new Date(a.json.createdTime));
const latest = mdFiles[0].json;
return [{ json: { hasPreviousSummary: true, latestSummaryId: latest.id, latestSummaryName: latest.name } }];
